import{_ as e,o as d,c as a,ag as o}from"./chunks/framework-C5-Jzrz4.js";const c=JSON.parse('{"title":"package.json 对比分析","description":"根 package.json、apps/web-antd 与 docs 子包配置差异","frontmatter":{"title":"package.json 对比分析","description":"根 package.json、apps/web-antd 与 docs 子包配置差异","lastUpdated":true},"headers":[],"relativePath":"scripts/analysis/package.json 对比分析.md","filePath":"scripts/analysis/package.json 对比分析.md","lastUpdated":null}');const i=e({name:"scripts/analysis/package.json 对比分析.md"},[["render",function(e,c,i,l,t,s){return d(),a("div",null,[...c[0]||(c[0]=[o('<h1 id="package-json-对比分析" tabindex="-1">package.json 对比分析 <a class="header-anchor" href="#package-json-对比分析" aria-label="Permalink to &quot;package.json 对比分析&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>本页只分析当前仓库真实配置：根目录、<code>apps/web-antd</code>、<code>docs</code> 三个 package 的职责边界。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>命令入口定位</li><li>依赖归属判断</li><li>文档站点与主应用构建差异识别</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>package.json</code></li><li><code>apps/web-antd/package.json</code></li><li><code>docs/package.json</code></li><li><code>pnpm-workspace.yaml</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="角色分工" tabindex="-1">角色分工 <a class="header-anchor" href="#角色分工" aria-label="Permalink to &quot;角色分工&quot;">​</a></h3><table tabindex="0"><thead><tr><th>位置</th><th>包名</th><th>角色</th></tr></thead><tbody><tr><td>根目录</td><td><code>vben-admin-monorepo</code></td><td>Monorepo 编排层（Turbo、质量检查、统一命令）</td></tr><tr><td>应用</td><td><code>@vben/web-antd</code></td><td>业务应用运行层（Vite dev/build/preview）</td></tr><tr><td>文档</td><td><code>@lxy/docs</code></td><td>VitePress 文档站点</td></tr></tbody></table><h3 id="scripts-差异-核心命令" tabindex="-1">scripts 差异（核心命令） <a class="header-anchor" href="#scripts-差异-核心命令" aria-label="Permalink to &quot;scripts 差异（核心命令）&quot;">​</a></h3><p>根目录：</p><ul><li><code>dev</code>、<code>dev:antd</code></li><li><code>build</code>、<code>build:antd</code>、<code>build:antd:test</code></li><li><code>docs:dev</code>、<code>docs:build</code>、<code>docs:preview</code></li><li><code>lint</code>、<code>check:type</code>、<code>check</code></li></ul><p><code>apps/web-antd</code>：</p><ul><li><code>dev</code></li><li><code>build:prod</code></li><li><code>build:test</code></li><li><code>build:analyze</code></li><li><code>preview</code></li><li><code>typecheck</code></li></ul><p><code>docs</code>：</p><ul><li><code>dev</code>（<code>vitepress dev</code>）</li><li><code>build</code>（<code>vitepress build</code>）</li><li><code>preview</code>（<code>vitepress preview</code>）</li></ul><h3 id="依赖归属" tabindex="-1">依赖归属 <a class="header-anchor" href="#依赖归属" aria-label="Permalink to &quot;依赖归属&quot;">​</a></h3><ul><li>根目录以 <code>devDependencies</code> 为主，负责工程工具链</li><li><code>apps/web-antd</code> 以运行时依赖为主，引用大量 <code>workspace:*</code> 内部包</li><li><code>docs</code> 只保留 <code>vitepress</code> 相关依赖，职责单一</li></ul><h3 id="版本与环境约束" tabindex="-1">版本与环境约束 <a class="header-anchor" href="#版本与环境约束" aria-label="Permalink to &quot;版本与环境约束&quot;">​</a></h3><p>根目录定义：</p><ul><li><code>engines.node = ^20.19.0 || ^22.18.0 || ^24.0.0</code></li><li><code>engines.pnpm &gt;= 10.0.0</code></li><li><code>packageManager = pnpm@10.32.1</code></li></ul><p>应用与 docs 未重复声明，默认继承根目录开发约束。</p><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>新增通用命令优先放根目录，避免子包命令分散。</li><li>新增业务运行依赖放 <code>apps/web-antd</code>，不要误放根目录。</li><li>文档站点能力仅在 <code>docs</code> 子包维护，保持与业务应用解耦。</li></ul>',25)])])}]]);export{c as __pageData,i as default};
